def solve(n: Long, edges: Array[Array[Long]], k: Long): Long = {
  val parent = Array.ofDim[Int](n.toInt)
  val rank = Array.ofDim[Int](n.toInt)

  for (i <- 0 until n.toInt) {
    parent(i) = i
    rank(i) = 0
  }

  def find(u: Int): Int = {
    if (parent(u) != u) {
      parent(u) = find(parent(u))
    }
    parent(u)
  }

  def union(u: Int, v: Int): Boolean = {
    val rootU = find(u)
    val rootV = find(v)
    if (rootU == rootV) false
    else {
      if (rank(rootU) > rank(rootV)) {
        parent(rootV) = rootU
      } else if (rank(rootU) < rank(rootV)) {
        parent(rootU) = rootV
      } else {
        parent(rootV) = rootU
        rank(rootU) += 1
      }
      true
    }
  }

  val sortedEdges = edges.sortBy(_(2))
  var components = n.toInt
  var res = 0L

  for (edge <- sortedEdges) {
    if (components <= k.toInt) {
      return res
    }
    val u = edge(0).toInt
    val v = edge(1).toInt
    val w = edge(2)
    if (union(u, v)) {
      components -= 1
      res = res.max(w)
    }
  }

  res
}
